INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', $q$Workflow Definition in YAML or HUML$q$, $q$Workflows are defined as version-controlled configuration files using either standard YAML or HUML (Human-oriented Markup Language), a newer strict configuration format, letting teams specify inputs, actions, and approval gates as code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', $q$Approval Gates$q$, $q$Sensitive workflow steps can require sign-off from a designated approver before execution continues, giving teams a built-in change-control mechanism for high-risk operations like production access or infrastructure changes.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', $q$Remote Execution over SSH$q$, $q$Workflow actions can run locally on the flowctl server or be dispatched concurrently across multiple remote nodes over SSH, enabling fleet-wide operations from a single workflow run.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', $q$Cron-Based Scheduling$q$, $q$Workflows support multiple cron schedules so recurring operations, such as database maintenance or credential rotation, can run automatically without manual triggering.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', $q$OIDC SSO and Role-Based Access Control$q$, $q$Authentication integrates with any OIDC-compliant identity provider, with support for automatic user provisioning and domain-restricted sign-ups, while RBAC and team or project namespace isolation control who can view, run, or approve each workflow.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', $q$Encrypted Secrets Storage$q$, $q$A built-in keystore encrypts sensitive values such as SSH keys and passwords at rest, so workflows can reference credentials without exposing them in plain text configuration files.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', $q$Real-Time Streaming Logs and Execution History$q$, $q$The web interface streams logs from running actions live and retains a searchable history of past executions, including status and results, for auditability.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', $q$Artifacts and Retry Handling$q$, $q$Actions can produce file-based artifacts that later steps in the same workflow consume, and failed actions can be automatically retried according to configurable retry policies.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', $q$Free and fully open source under the Apache 2.0 license, with no licensing cost or paid tier$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', $q$Single binary with only PostgreSQL as an external dependency, making self-hosting simple compared to multi-service alternatives$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', $q$Combines workflow automation with access-control features (approvals, RBAC, OIDC SSO, encrypted secrets) that many teams otherwise assemble from separate tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', $q$Actively developed, with 44 releases published within roughly nine months and ongoing commits$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', $q$Very young project (created October 2025) with a small community (roughly 325 GitHub stars and 22 forks) and a limited plugin and integration ecosystem compared to mature tools like Rundeck or Ansible AWX$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', $q$No official Windows binaries; only Linux and macOS builds are published in releases$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', $q$Requires self-hosting a PostgreSQL instance and the binary yourself; there is no managed cloud or SaaS offering$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', $q$Support is limited mainly to GitHub issues, and the project relies heavily on a single primary maintainer$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', $q$What is flowctl?$q$, $q$flowctl is a free, open-source, single-binary workflow automation platform that lets teams define operational workflows, such as granting temporary SSH access, provisioning infrastructure, or running maintenance jobs, as YAML or HUML configuration files, then expose them through a self-hosted web interface with built-in approvals, scheduling, and role-based access control.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', $q$Is flowctl free to use?$q$, $q$Yes. flowctl is licensed under the Apache 2.0 license and is entirely free to download, self-host, and modify. There is no paid tier, subscription, or hosted SaaS version; the only cost is the infrastructure a team uses to run the binary and its required PostgreSQL database.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', $q$Who built flowctl?$q$, $q$flowctl is developed and maintained on GitHub under the handle cvhariharan by Hariharan, a software engineer who works on DevOps and infrastructure. It is presented as an independent open-source project rather than a product of a specific company.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', $q$What are the system requirements to run flowctl?$q$, $q$flowctl runs as a single compiled binary (or via the provided Docker Compose setup) and requires only a PostgreSQL database as an external dependency. Official binaries are published for Linux (x86_64, arm64, and armv7) and macOS (x86_64 and arm64); no official Windows build is provided.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', $q$How does flowctl compare to Rundeck or Ansible AWX?$q$, $q$flowctl positions itself as a lighter-weight alternative to Rundeck, offering similar self-service job execution, approvals, and RBAC without a JVM runtime or commercial enterprise edition. Compared with Ansible AWX, flowctl is not tied to Ansible playbooks and treats approval gates and OIDC SSO as first-class concepts rather than add-ons.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', $q$Does flowctl support single sign-on?$q$, $q$Yes. flowctl integrates with OIDC-compliant identity providers for SSO, and its configuration supports automatic user creation on first login as well as restricting sign-ups to approved email domains.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', $q$Self-service infrastructure access$q$, $q$Platform teams define workflows that grant time-boxed SSH access or provision cloud resources on request, with an approval gate ensuring a human signs off before access is granted, reducing standing access and manual ticket handling.$q$, $q$Platform and DevOps teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', $q$Operational runbooks with approvals$q$, $q$SRE and operations teams codify sensitive runbooks, such as database maintenance, credential rotation, or production configuration changes, as flowctl workflows so they run consistently, get logged, and require sign-off before execution.$q$, $q$Site reliability and operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', $q$Internal business process automation$q$, $q$Because flowctl's executor architecture is domain-agnostic, teams outside of infrastructure can use it to automate custom internal business processes, exposing them as self-service forms with cron scheduling and access control instead of building bespoke internal tools.$q$, $q$Internal tooling and backend engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', $q$Open Source$q$, $q$Free$q$, $q$Self-hosted, no billing$q$, NULL, $q$["Apache 2.0 licensed source code","Unlimited workflows, users, and executions","Single-binary or Docker Compose self-hosted deployment","OIDC SSO, RBAC, approvals, and encrypted secrets included","Community support via GitHub issues and pull requests"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$flowctl is a free, open-source, self-hosted workflow automation platform packaged as a single binary. It lets engineering and operations teams define workflows, such as granting temporary SSH access, provisioning infrastructure, running database maintenance, or automating internal business processes, as version-controlled YAML or HUML configuration files, then expose them to authorized users through a web interface with approvals, role-based access control, and audit logging.$q$, $q$The project's public GitHub repository was created on October 30, 2025, and is authored and maintained by a developer known as cvhariharan (Hariharan), a software engineer who works on DevOps and infrastructure. It is presented as an independent open-source project rather than a commercially backed product, and it is written in Go on the backend with a Svelte and TypeScript frontend, licensed under Apache 2.0.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Workflows in flowctl are defined declaratively with inputs, a sequence of actions, and optional approval gates that pause execution until a designated approver signs off. Actions can run locally or be dispatched over SSH to multiple remote nodes concurrently, and workflows can be triggered on demand or automatically via one or more cron schedules.$q$, $q$Security and governance are built in rather than bolted on: authentication integrates with OIDC identity providers for single sign-on, RBAC and team or project namespace isolation control who can view, run, or approve each workflow, and an internal keystore encrypts secrets such as SSH keys and passwords at rest. The web UI streams execution logs in real time, retains execution history, passes file-based artifacts between workflow steps, and can automatically retry failed actions.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$flowctl has no pricing tiers, paid edition, or hosted SaaS offering. The entire codebase is published under the Apache 2.0 license, allowing free commercial and non-commercial use, modification, and self-hosted redistribution, and there is no pricing page on flowctl.net.$q$, $q$A public live demo is available at demo.flowctl.net so prospective users can try the web interface before deploying it. Production use requires self-hosting the binary (or its Docker image) alongside a PostgreSQL database that the adopting team provisions and operates itself, so the only real costs are the infrastructure used to run flowctl, not the software.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('4bc25f51-5006-4396-aeab-6860c203eba6', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', $q$Node-RED visual flow editor$q$, $q$A browser-based, drag-and-drop canvas for wiring together devices, APIs, databases, and services using a large ecosystem of community and certified nodes.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', $q$DevOps Pipelines$q$, $q$Promote a flow through development, test, and production instances with staged rollouts and one-click promotion between environments.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', $q$Device Agent for edge fleets$q$, $q$Deploy and remotely monitor Node-RED logic across hundreds or thousands of edge devices in factories, plants, or the field from a single dashboard.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', $q$Version history and snapshots$q$, $q$Automatic snapshots of instance state let teams review changes over time and roll back to a previous working flow if something breaks.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', $q$Team collaboration and RBAC$q$, $q$Multiple developers can work against the same instance with role-based access control governing who can view, edit, or deploy flows.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', $q$Enterprise security (SSO and audit logs)$q$, $q$TLS/SSL encryption, SAML-based single sign-on, and full audit logging of configuration and flow changes for compliance-sensitive teams.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', $q$Built-in MQTT broker$q$, $q$An included MQTT broker supports lightweight machine-to-machine messaging common in industrial and IoT deployments, with client limits that scale by plan.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', $q$FlowFuse Expert AI assistant and Blueprints$q$, $q$An AI assistant generates starter flows from plain-language descriptions, and a library of Blueprint templates accelerates common integration and dashboard patterns.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', $q$Built and maintained by the original creators and lead maintainers of the open-source Node-RED project, so the roadmap stays tightly aligned with the underlying runtime.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', $q$Free, fully open-source self-hosted tier available for evaluation or small teams before committing to a paid plan.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', $q$Purpose-built for industrial IoT and edge scenarios, with device-fleet management and staged DevOps Pipelines that generic automation tools do not offer.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', $q$SOC 2 Type 1 and Type 2 certifications, plus self-hosted and air-gapped deployment options for regulated enterprises.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', $q$The August 2023 rebrand to FlowFuse means the FlowForge name and flowforge.com domain no longer point to an actively marketed brand, which can confuse users searching under the old name.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', $q$Paid Cloud and Self-Hosted Pro tiers jump from a low-cost Starter plan to 425 dollars per month, a steep step for small teams outgrowing the free or Starter tier.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', $q$Enterprise pricing is not published and requires a sales conversation, making upfront budgeting harder for prospective customers.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', $q$Node-RED's low-code flow model still requires developer-level familiarity with JavaScript, protocols, and data structures for anything beyond simple wiring, so it is not a true no-code tool for non-technical business users.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', $q$Is FlowForge the same company as FlowFuse?$q$, $q$Yes. FlowForge Inc. rebranded its product and public identity to FlowFuse in August 2023 after a trademark dispute over the FlowForge name. The team, technology, and product roadmap did not change, and flowforge.com now redirects to flowfuse.com.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', $q$What is the relationship between FlowForge and Node-RED?$q$, $q$Node-RED is the open-source flow-based programming tool created by Nick O'Leary at IBM in 2013. FlowForge is the company Nick O'Leary later founded in 2021 to commercialize Node-RED, adding hosting, device management, DevOps Pipelines, and enterprise security on top of the open-source runtime.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', $q$Can I use FlowForge for free?$q$, $q$Yes. The Self-Hosted Starter tier is free and fully open source, supporting up to five Node-RED instances and five team members, making it suitable for evaluation, hobby projects, or small deployments before upgrading to a paid Cloud or Pro tier.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', $q$Who founded FlowForge and when?$q$, $q$FlowForge was founded in 2021 by Nick O'Leary, the creator and lead maintainer of Node-RED, who serves as CTO. Zeger-Jan van de Weg, an early GitLab employee, joined as CEO in January 2022. The company is headquartered in San Francisco, California.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', $q$How much funding has FlowForge raised?$q$, $q$FlowForge raised an initial 2 million dollars from GitLab CEO Sid Sijbrandij through Open Core Ventures, followed by a 7.2 million dollar seed round in November 2022 led by Cota Capital, Westwave Capital, Uncorrelated Ventures, and Open Core Ventures, bringing total disclosed funding to roughly 14.5 million dollars.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', $q$What are the main alternatives to FlowForge?$q$, $q$Alternatives include self-hosting open-source Node-RED without a commercial layer, general workflow automation tools like n8n, Zapier, and Make, and industrial automation platforms such as Ignition by Inductive Automation and Tulip, though FlowForge is differentiated by being built by Node-RED's original maintainers and focused on edge device fleets.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', $q$Industrial IoT and factory floor integration$q$, $q$Manufacturing teams use FlowForge to connect shop-floor equipment, SCADA and MES systems, and enterprise software into unified data flows without writing brittle point-to-point integrations, deploying the same logic across many production lines with the Device Agent.$q$, $q$Manufacturing and industrial automation engineers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', $q$Managed hosting for existing Node-RED users$q$, $q$Teams that previously ran unsupported, self-managed Node-RED instances migrate to FlowForge for production-grade hosting, automated backups, version history, and role-based access control without giving up the flow editor they already know.$q$, $q$DevOps and platform engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', $q$Edge device fleet management$q$, $q$Organizations with hundreds or thousands of remote devices use FlowForge's Device Agent and DevOps Pipelines to push flow updates, monitor device health, and stage rollouts across development, test, and production environments.$q$, $q$IoT solution providers and systems integrators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', $q$Cloud Starter$q$, $q$$20/month (after a free Pro trial)$q$, $q$monthly$q$, NULL, $q$["1 hosted instance, upgradable to 3 hosted or 3 remote instances","Up to 2 team members","FlowFuse Expert AI assistant included","Access to Blueprint templates"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', $q$Cloud Pro$q$, $q$$425/month (discounted with annual billing)$q$, $q$monthly or annual$q$, NULL, $q$["5 hosted or remote instances","Up to 20 team members","MQTT broker with 8 clients","Standard support with 99.5% uptime SLA"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', $q$Cloud Enterprise$q$, $q$Custom quote$q$, $q$annual (contract)$q$, NULL, $q$["20+ hosted or remote instances","Unlimited team members","Single sign-on (SAML)","MQTT broker with 20 clients, device group management, 99.9% uptime SLA"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', $q$Self-Hosted Starter$q$, $q$Free$q$, $q$n/a (open source)$q$, NULL, $q$["Up to 5 instances","Up to 5 team members","Open-source FlowForge/FlowFuse platform for evaluation and small deployments"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', $q$Self-Hosted Pro$q$, $q$$425/month$q$, $q$billed annually$q$, NULL, $q$["5 instances","Up to 20 team members","Installation support and dedicated success management"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', $q$Self-Hosted Enterprise$q$, $q$Custom quote or trial license$q$, $q$annual (contract)$q$, NULL, $q$["20+ instances","Unlimited team members","Air-gapped and on-premises deployment support"]$q$::jsonb, 5);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$FlowForge is the commercial company built around Node-RED, the open-source flow-based low-code tool used to wire together hardware devices, APIs, and online services on a visual, browser-based canvas. Rather than replacing Node-RED, FlowForge adds the hosting, governance, and device-fleet management layer that turns individual open-source Node-RED instances into a production-grade platform for teams and enterprises.$q$, $q$The company was founded in 2021 by Nick O'Leary, the original creator and lead maintainer of Node-RED, who first built the tool at IBM in 2013. In August 2023 the company rebranded from FlowForge to FlowFuse following a trademark dispute; the underlying product, team, and technology stayed the same, and flowforge.com now redirects to flowfuse.com.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform's core additions on top of the Node-RED editor include centralized management of multiple instances, a Device Agent for deploying and monitoring flows across hundreds or thousands of remote edge devices, and DevOps Pipelines that promote a flow through development, test, and production environments with rollback support via version-history snapshots.$q$, $q$Enterprise features cover role-based access control, single sign-on through SAML providers, audit logging, an integrated MQTT broker for machine-to-machine messaging, high-availability scaling with automatic failover, and both cloud-hosted and self-hosted (including air-gapped) deployment options. An AI assistant called FlowFuse Expert can generate starter flows from plain-language descriptions, and a Blueprints library provides pre-built templates for common integration patterns.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pricing splits into Cloud-hosted and Self-Hosted tracks, each with Starter, Pro, and Enterprise tiers. Cloud Starter runs 20 dollars per month after a free Pro trial with one to three instances and two team members; Cloud Pro is 425 dollars per month (discounted annually) with five instances, twenty team members, an MQTT broker, and a 99.5 percent SLA; Cloud Enterprise is quote-based with unlimited seats, SSO, and a 99.9 percent SLA.$q$, $q$The Self-Hosted Starter tier is free and fully open source, supporting up to five instances and five team members for evaluation or small deployments. Self-Hosted Pro costs 425 dollars per month billed annually and adds installation support, while Self-Hosted Enterprise is quote or trial-license based for organizations that need everything running on their own infrastructure.$q$]::text[], 2);
