INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1ae3dedf-781d-4eba-bac7-7d80412bd2db', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$Drag-and-drop flow builder$q$, $q$A visual node-graph canvas for assembling LLM chains, RAG pipelines, and agent logic without writing orchestration code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$Chatflows for conversational AI$q$, $q$Single-agent chatbot flows with tool calling and retrieval-augmented generation support from PDFs, spreadsheets, websites, and other sources.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$Agentflows for multi-agent systems$q$, $q$Coordinated, multi-step agent workflows that can include human-in-the-loop checkpoints for review before an action is completed.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$100+ model and vector store integrations$q$, $q$Native support for over 100 LLM providers, embedding models, and vector databases, including OpenAI, Anthropic, Pinecone, Weaviate, and Chroma.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$APIs, SDKs, and embeddable widgets$q$, $q$Every flow can be exposed as a REST API, embedded as a chat widget on a website, or called through official TypeScript and Python SDKs.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$Observability and monitoring$q$, $q$Full execution traces compatible with OpenTelemetry and Prometheus for tracking agent behavior and performance in production.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$Self-hosting and open-source core$q$, $q$The core project is Apache 2.0 licensed and can be self-hosted for free via Docker or deployed to AWS, Azure, Google Cloud, or DigitalOcean.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$Enterprise security controls$q$, $q$SSO/SAML, role-based access control, audit logging, and on-premises or air-gapped deployment options for enterprise customers.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$Free and open source under the permissive Apache 2.0 license, with no-cost self-hosting available on any infrastructure.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$Visual, drag-and-drop interface lowers the barrier to building RAG chatbots and multi-agent systems compared to writing LangChain code by hand.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$Broad integration coverage across more than 100 LLMs, embedding models, and vector databases.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$Supports both simple chatbots and more complex, coordinated multi-agent workflows with human-in-the-loop review.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$Flowise Cloud subscription prices do not include LLM token usage, so real production costs can run well above the listed plan price once model API bills are added.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$Self-hosting requires comfort with Docker and cloud infrastructure, which adds setup and maintenance overhead for non-technical teams.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$Enterprise pricing is not published and must be negotiated directly with sales, making budgeting harder for larger deployments.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$As a very small, now Workday-owned team historically, long-term open-source roadmap priorities may increasingly reflect Workday's enterprise product needs rather than the broader community's.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$Is Flowise free to use?$q$, $q$Yes. The core Flowise platform is open source under the Apache 2.0 license and can be self-hosted for free. Flowise also offers a managed Flowise Cloud Free plan with limited flows and predictions per month, alongside paid Starter, Pro, and Enterprise tiers for higher usage and additional features.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$Who owns Flowise now?$q$, $q$Flowise was founded in 2023 by Henry Heng and Chung Yau Ong and was backed by Y Combinator. In August 2025, enterprise software company Workday acquired Flowise to power AI agent building across its own platform; the open-source project and Flowise Cloud continue to operate under Workday's ownership.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$What is the difference between Flowise's Chatflows and Agentflows?$q$, $q$Chatflows are single-agent conversational flows designed for chatbots and RAG-based assistants. Agentflows support multi-agent systems where several specialized agents coordinate on more complex tasks, optionally pausing for human-in-the-loop review before continuing.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$Does Flowise require coding knowledge?$q$, $q$No coding is required to build a basic flow, since Flowise uses a drag-and-drop visual canvas. However, developers can extend Flowise with custom tools, functions, and API integrations using TypeScript or Python for more advanced use cases.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$How does Flowise compare to Langflow, n8n, and Dify?$q$, $q$Flowise, Langflow, and Dify are all open-source, visual tools for building LLM applications, while n8n is a broader workflow-automation platform that has added AI nodes. Flowise differentiates itself with its Apache 2.0 license, dual TypeScript/Python SDKs, and tight focus on RAG and multi-agent orchestration.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$Can Flowise be self-hosted for data privacy or compliance reasons?$q$, $q$Yes. Because the core project is open source, organizations can self-host Flowise on their own infrastructure or private cloud, and the Enterprise tier additionally supports on-premises or air-gapped deployment along with SSO/SAML and audit logging for regulated environments.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$Rapid RAG chatbot prototyping$q$, $q$Developers connect a document loader, vector store, and chat model on the Flowise canvas to stand up a retrieval-augmented chatbot over internal knowledge bases in minutes rather than writing custom LangChain code.$q$, $q$Individual developers and indie builders$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$Internal enterprise AI assistants$q$, $q$Product and IT teams use Flowise's Chatflows and Agentflows to build customer-support bots, internal knowledge assistants, and multi-step business process agents that plug into existing enterprise data sources.$q$, $q$Small and medium-sized business teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$Governed, large-scale agent deployment$q$, $q$Large organizations use Flowise's Enterprise tier, with SSO/SAML, RBAC, audit logging, and on-premises deployment, to design, launch, and govern AI agents at scale across regulated business units.$q$, $q$Enterprises and platform teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["2 flows","100 predictions per month","5 MB storage","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$Starter$q$, $q$$35/month$q$, $q$monthly$q$, NULL, $q$["Unlimited flows","10,000 predictions per month","1 GB storage"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$Pro$q$, $q$$65/month$q$, $q$monthly$q$, NULL, $q$["50,000 predictions per month","10 GB storage","Unlimited workspaces","User management"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$Enterprise$q$, $q$Custom$q$, $q$annual (negotiated)$q$, NULL, $q$["SSO and SAML","Role-based access control","Audit logs","On-premises or air-gapped deployment","Dedicated support"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full core platform under Apache 2.0 license","Self-host via Docker or any cloud provider","No usage limits imposed by Flowise itself"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Flowise is an open-source, low-code platform for visually building LLM applications, RAG chatbots, and multi-agent AI systems. Instead of writing orchestration code, users drag and connect nodes representing language models, prompts, memory, tools, vector stores, and agent logic onto a canvas to assemble a working AI flow.$q$, $q$Founded in 2023 by Henry Heng and Chung Yau Ong and backed by Y Combinator, the project grew into one of the most starred open-source AI agent-builder repositories on GitHub before being acquired by Workday in August 2025, which now uses Flowise's technology to power AI agent creation across its own enterprise platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Flowise supports two main flow types: Chatflows for single-agent conversational assistants with RAG support, and Agentflows for coordinated multi-agent systems that can include human-in-the-loop review checkpoints before an action is finalized.$q$, $q$The platform integrates with more than 100 LLM providers, embedding models, and vector databases, exposes flows as REST APIs, embeddable chat widgets, and TypeScript/Python SDKs, and provides observability through OpenTelemetry- and Prometheus-compatible execution traces for production monitoring.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$how-it-works$q$, $q$How Flowise Works$q$, 2, ARRAY[$q$Flowise's canvas is built on a node-graph editor where each node represents a discrete building block, such as a chat model, a document loader, a vector store retriever, or a custom tool. Users connect these nodes to define how data and control flow through the application, drawing on LangChain-style abstractions under the hood.$q$, $q$The underlying codebase is written primarily in TypeScript and JavaScript, with a React front-end and Node.js backend, and is released under the Apache 2.0 license. This lets organizations self-host Flowise for free on Docker or any major cloud provider, including AWS, Azure, Google Cloud, and DigitalOcean, while retaining full control over data and infrastructure.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Flowise offers two pricing tracks: a free, self-hosted open-source option, and a managed Flowise Cloud with a Free plan, a Starter plan at roughly $35 per month, and a Pro plan at roughly $65 per month, each raising limits on predictions per month, storage, and workspace or user management.$q$, $q$An Enterprise tier with custom pricing adds SSO/SAML, role-based access control, audit logging, dedicated support, and on-premises or air-gapped deployment options for organizations with strict security or compliance needs. LLM token usage from providers like OpenAI or Anthropic is typically billed separately from the Flowise subscription itself.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', $q$competitors$q$, $q$Competitors and Alternatives$q$, 2, ARRAY[$q$Flowise is most often compared to Langflow, another open-source visual LangChain-style flow builder; n8n, a broader workflow-automation platform that has added AI and LLM nodes; Dify, an open-source LLMOps platform with more opinionated application templates; and LangChain/LangGraph, the underlying code-first frameworks that tools like Flowise wrap in a visual interface.$q$, $q$Flowise differentiates itself with its permissive Apache 2.0 license, dual TypeScript and Python SDK support, tight focus on visual agent and RAG orchestration rather than general business-process automation, and, since its 2025 acquisition, the enterprise distribution and credibility that comes from being owned by Workday.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a24c79b2-2532-4586-980b-a77abc122161', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
